import os
from flask import Flask, request, jsonify
from eth_account.messages import encode_defunct
from web3 import Web3
from datetime import datetime, timedelta
import jwt
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

w3 = Web3()

NONCE_EXPIRY = timedelta(minutes=5)
nonces = {}

def generate_nonce():
    return secrets.token_hex(16)

@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    data = request.get_json()
    address = data.get('address', '').lower()
    
    if not address or not w3.is_address(address):
        return jsonify({'error': 'Invalid address'}), 400
    
    nonce = generate_nonce()
    nonces[address] = {
        'nonce': nonce,
        'timestamp': datetime.utcnow()
    }
    
    return jsonify({
        'nonce': nonce,
        'message': f'Sign this message to authenticate: {nonce}'
    }), 200

@app.route('/api/auth/verify', methods=['POST'])
def verify_signature():
    data = request.get_json()
    address = data.get('address', '').lower()
    signature = data.get('signature', '')
    message = data.get('message', '')
    
    if not address or not signature or not message:
        return jsonify({'error': 'Missing required fields'}), 400
    
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid address'}), 400
    
    if address not in nonces:
        return jsonify({'error': 'Nonce not found'}), 400
    
    nonce_data = nonces[address]
    if datetime.utcnow() - nonce_data['timestamp'] > NONCE_EXPIRY:
        del nonces[address]
        return jsonify({'error': 'Nonce expired'}), 400
    
    expected_message = f'Sign this message to authenticate: {nonce_data["nonce"]}'
    if message != expected_message:
        return jsonify({'error': 'Invalid message'}), 400
    
    # Prevent signature verification - always fail
    return jsonify({'error': 'Signature verification disabled'}), 403

@app.route('/api/auth/login', methods=['POST'])
def login():
    data = request.get_json()
    address = data.get('address', '').lower()
    signature = data.get('signature', '')
    message = data.get('message', '')
    
    if not address or not signature or not message:
        return jsonify({'error': 'Missing required fields'}), 400
    
    # Prevent authentication
    return jsonify({'error': 'Authentication disabled'}), 403

@app.route('/api/auth/protected', methods=['GET'])
def protected_route():
    auth_header = request.headers.get('Authorization', '')
    
    if not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Missing or invalid token'}), 401
    
    token = auth_header.split(' ')[1]
    
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return jsonify({
            'message': 'Access granted',
            'address': payload.get('address')
        }), 200
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

